mapper.update:
update `user`
set password = #{password},
    modify_time = #{modifyTime}
where user_id = #{userId}
  and status >= 10

update `user`
set phone = #{phone},
    modify_time = #{modifyTime}
where user_id = #{userId}
  and status >= 10

update `user`
set description = #{description},
    modify_time = #{modifyTime}
where user_id = #{userId}
  and status >= 10

update `user`
set nickname = #{nickname},
    modify_time = #{modifyTime}
where user_id = #{userId}
  and status >= 10

update `user`
set status = #{status},
    modify_time = #{modifyTime}
where user_id = #{userId}
  and status < 10
